{"content": "     1|/**
     2| * @module dispatcher
     3| * @description Route parsed GSD tasks to the correct agent platform:
     4| * Paperclip (wakeup API), OpenClaw (relay), or Hermes (direct execution).
     5| * Supports wave-aware sequential dispatch.
     6| */
     7|
     8|import { readFile } from 'node:fs/promises';
     9|import { join, dirname } from 'node:path';
    10|import { groupByWave } from './parser.js';
    11|
    12|// ─── Config-Driven Agent Mappings ───────────────────────────────────────────────
    13|
    14|/** @type {Object|null} Cached config loaded from .planning/config.json */
    15|let _config = null;
    16|
    17|/**
    18| * Load and cache routing config from the nearest .planning/config.json.
    19| * Falls back to env vars if config file isn't available.
    20| *
    21| * @param {string} [configPath] - Explicit path to config.json
    22| * @returns {Promise<Object>}
    23| */
    24|async function getConfig(configPath) {
    25|  if (_config) return _config;
    26|
    27|  // Try loading config file
    28|  const paths = configPath
    29|    ? [configPath]
    30|    : ['.planning/config.json', '../.planning/config.json'];
    31|
    32|  for (const p of paths) {
    33|    try {
    34|      const raw = await readFile(p, 'utf-8');
    35|      _config = JSON.parse(raw);
    36|      return _config;
    37|    } catch { /* try next */ }
    38|  }
    39|
    40|  // Fallback: build config from env vars only
    41|  _config = { agents: {}, mission_control: {} };
    42|  return _config;
    43|}
    44|
    45|/**
    46| * Reset cached config (useful for testing or config reload).
    47| */
    48|export function resetConfig() {
    49|  _config = null;
    50|}
    51|
    52|/**
    53| * Build case-insensitive Paperclip agent UUID map from config.
    54| * @param {Object} config
    55| * @returns {Object}
    56| */
    57|function buildPaperclipAgents(config) {
    58|  const ids = config?.agents?.paperclip?.ids || {};
    59|  const map = {};
    60|  for (const [name, uuid] of Object.entries(ids)) {
    61|    map[name] = uuid;
    62|    map[name.toLowerCase()] = uuid;
    63|  }
    64|  return map;
    65|}
    66|
    67|/** Assignee slugs that resolve to OpenClaw agents (relayed via relay server) */
    68|const OPENCLAW_AGENTS = new Set([
    69|  'openclaw/main',
    70|  'openclaw/coder',
    71|  'roscoe',
    72|  'coder',
    73|]);
    74|
    75|/** Assignee slugs that resolve to Hermes direct execution */
    76|const HERMES_AGENTS = new Set([
    77|  'hermes-ceo',
    78|  'hermes',
    79|]);
    80|
    81|// ─── Auth / Config (from environment variables) ────────────────────────────────
    82|
    83|function getPaperclipBase(config) {
    84|  return config?.agents?.paperclip?.url
    85|    || process.env.PAPERCLIP_BASE_URL
    86|    || 'https://agents.lawyerincorporated.com';
    87|}
    88|
    89|function getPaperclipAuth() {
    90|  return {
    91|    email: process.env.PAPERCLIP_AUTH_EMAIL,
    92|    password: process.env.PAPERCLIP_AUTH_PASSWORD,
    93|  };
    94|}
    95|
    96|function getRelayBase(config) {
    97|  return config?.agents?.relay?.url
    98|    || process.env.RELAY_BASE_URL
    99|    || 'https://relay.lawyerincorporated.com';
   100|}
   101|
   102|function getRelaySecret() {
   103|  return process.env.RELAY_SECRET || '';
   104|}
   105|
   106|/** Cached Paperclip auth token */
   107|let _paperclipToken = null;
   108|let _paperclipTokenExpiry = 0;
   109|
   110|/**
   111| * @typedef {Object} DispatchResult
   112| * @property {string} taskId
   113| * @property {string} assignee
   114| * @property {'paperclip'|'openclaw'|'hermes'|'unknown'} platform
   115| * @property {boolean} success
   116| * @property {number|null} status
   117| * @property {any} response
   118| * @property {string|null} error
   119| */
   120|
   121|// ─── Platform Detection ────────────────────────────────────────────────────────
   122|
   123|/**
   124| * Determine which platform an assignee belongs to.
   125| *
   126| * @param {string} assignee - The task assignee slug
   127| * @param {Object} [config] - Loaded config (if available)
   128| * @returns {'paperclip'|'openclaw'|'hermes'|'unknown'}
   129| */
   130|export function detectPlatform(assignee, config) {
   131|  const slug = assignee.toLowerCase();
   132|  if (HERMES_AGENTS.has(slug) || HERMES_AGENTS.has(assignee)) return 'hermes';
   133|  if (OPENCLAW_AGENTS.has(slug) || OPENCLAW_AGENTS.has(assignee)) return 'openclaw';
   134|  const paperclipAgents = config ? buildPaperclipAgents(config) : {};
   135|  if (paperclipAgents[assignee] || paperclipAgents[slug]) return 'paperclip';
   136|  return 'unknown';
   137|}
   138|
   139|// ─── Paperclip Auth ────────────────────────────────────────────────────────────
   140|
   141|/**
   142| * Authenticate with Paperclip and cache the bearer token.
   143| *
   144| * @param {Object} config - Loaded config
   145| * @returns {Promise<string>} Bearer token
   146| */
   147|async function getPaperclipToken(config) {
   148|  if (_paperclipToken && Date.now() < _paperclipTokenExpiry) {
   149|    return _paperclipToken;
   150|  }
   151|
   152|  const auth = getPaperclipAuth();
   153|  if (!auth.email || !auth.password) {
   154|    throw new Error(
   155|      'Paperclip credentials not configured. Set PAPERCLIP_AUTH_EMAIL and PAPERCLIP_AUTH_PASSWORD env vars.'
   156|    );
   157|  }
   158|
   159|  const base = getPaperclipBase(config);
   160|  const res = await fetch(`${base}/api/auth/login`, {
   161|    method: 'POST',
   162|    headers: { 'Content-Type': 'application/json' },
   163|    body: JSON.stringify(auth),
   164|  });
   165|
   166|  if (!res.ok) {
   167|    const text = await res.text();
   168|    throw new Error(`Paperclip auth failed (${res.status}): ${text}`);
   169|  }
   170|
   171|  const data = await res.json();
   172|  _paperclipToken = data.token || data.access_token || data.jwt;
   173|  // Cache for 55 minutes
   174|  _paperclipTokenExpiry = Date.now() + 55 * 60 * 1000;
   175|  return _paperclipToken;
   176|}
