   178|// ─── Dispatch Functions ────────────────────────────────────────────────────────
   179|
   180|/**
   181| * Dispatch a task to a Paperclip agent via the wakeup API.
   182| *
   183| * @param {import('./parser.js').Task} task - The task to dispatch
   184| * @returns {Promise<DispatchResult>}
   185| */
   186|export async function dispatchToPaperclip(task) {
   187|  const config = await getConfig();
   188|  const paperclipAgents = buildPaperclipAgents(config);
   189|  const agentId = paperclipAgents[task.assignee] || paperclipAgents[task.assignee.toLowerCase()];
   190|  if (!agentId) {
   191|    return {
   192|      taskId: task.id,
   193|      assignee: task.assignee,
   194|      platform: 'paperclip',
   195|      success: false,
   196|      status: null,
   197|      response: null,
   198|      error: `No Paperclip agent UUID for assignee "${task.assignee}"`,
   199|    };
   200|  }
   201|
   202|  try {
   203|    const token = await getPaperclipToken(config);
   204|    const base = getPaperclipBase(config);
   205|
   206|    const wakeReason = [
   207|      `[GSD Task ${task.id}] ${task.title}`,
   208|      '',
   209|      `Type: ${task.type}`,
   210|      `Description: ${task.description}`,
   211|      '',
   212|      `Verification: ${task.verify}`,
   213|      `Done when: ${task.done}`,
   214|      task.approval ? `Requires approval: ${task.approval}` : '',
   215|    ].filter(Boolean).join('\n');
   216|
   217|    const res = await fetch(`${base}/api/agents/${agentId}/wakeup`, {
   218|      method: 'POST',
   219|      headers: {
   220|        'Content-Type': 'application/json',
   221|        'Authorization': `Bearer ${token}`,
   222|      },
   223|      body: JSON.stringify({
   224|        reason: wakeReason,
   225|        task_id: task.id,
   226|        task_type: task.type,
   227|        source: 'gsd-dispatcher',
   228|      }),
   229|    });
   230|
   231|    const body = await res.json().catch(() => res.text());
   232|
   233|    return {
   234|      taskId: task.id,
   235|      assignee: task.assignee,
   236|      platform: 'paperclip',
   237|      success: res.ok,
   238|      status: res.status,
   239|      response: body,
   240|      error: res.ok ? null : `Paperclip wakeup failed (${res.status})`,
   241|    };
   242|  } catch (err) {
   243|    return {
   244|      taskId: task.id,
   245|      assignee: task.assignee,
   246|      platform: 'paperclip',
   247|      success: false,
   248|      status: null,
   249|      response: null,
   250|      error: err.message,
   251|    };
   252|  }
   253|}
   254|
   255|/**
   256| * Dispatch a task to an OpenClaw agent via the relay server.
   257| *
   258| * @param {import('./parser.js').Task} task - The task to dispatch
   259| * @returns {Promise<DispatchResult>}
   260| */
   261|export async function dispatchToOpenClaw(task) {
   262|  const config = await getConfig();
   263|
   264|  // Map assignee to relay target name
   265|  const targetMap = {
   266|    'openclaw/main': 'openclaw-main',
   267|    'openclaw/coder': 'openclaw-coder',
   268|    'roscoe': 'openclaw-main',
   269|    'coder': 'openclaw-coder',
   270|  };
   271|
   272|  const target = targetMap[task.assignee.toLowerCase()] || task.assignee;
   273|
   274|  const chatPayload = [
   275|    `[GSD Task ${task.id}] ${task.title}`,
   276|    '',
   277|    `Type: ${task.type}`,
   278|    `Description: ${task.description}`,
   279|    '',
   280|    `Verification criteria: ${task.verify}`,
   281|    `Done when: ${task.done}`,
   282|    task.approval ? `Requires approval from: ${task.approval}` : '',
   283|  ].filter(Boolean).join('\n');
   284|
   285|  const relayBase = getRelayBase(config);
   286|  const relaySecret = getRelaySecret();
   287|  if (!relaySecret) {
   288|    return {
   289|      taskId: task.id,
   290|      assignee: task.assignee,
   291|      platform: 'openclaw',
   292|      success: false,
   293|      status: null,
   294|      response: null,
   295|      error: 'Relay secret not configured. Set RELAY_SECRET env var.',
   296|    };
   297|  }
   298|
   299|  try {
   300|    const res = await fetch(`${relayBase}/relay/send`, {
   301|      method: 'POST',
   302|      headers: {
   303|        'Content-Type': 'application/json',
   304|        'Authorization': `Bearer ${relaySecret}`,
   305|      },
   306|      body: JSON.stringify({
   307|        target,
   308|        message: chatPayload,
   309|        metadata: {
   310|          task_id: task.id,
   311|          task_type: task.type,
   312|          source: 'gsd-dispatcher',
   313|          wave: task.wave,
   314|        },
   315|      }),
   316|    });
   317|
   318|    const body = await res.json().catch(() => res.text());
   319|
   320|    return {
   321|      taskId: task.id,
   322|      assignee: task.assignee,
   323|      platform: 'openclaw',
   324|      success: res.ok,
   325|      status: res.status,
   326|      response: body,
   327|      error: res.ok ? null : `Relay send failed (${res.status})`,
   328|    };
   329|  } catch (err) {
   330|    return {
   331|      taskId: task.id,
   332|      assignee: task.assignee,
   333|      platform: 'openclaw',
   334|      success: false,
   335|      status: null,
   336|      response: null,
   337|      error: err.message,
   338|    };
   339|  }
