   342|/**
   343| * Handle a task assigned to Hermes for direct execution.
   344| * Returns the task payload for the calling orchestrator to execute.
   345| *
   346| * @param {import('./parser.js').Task} task - The task to handle
   347| * @returns {Promise<DispatchResult>}
   348| */
   349|export async function dispatchToHermes(task) {
   350|  return {
   351|    taskId: task.id,
   352|    assignee: task.assignee,
   353|    platform: 'hermes',
   354|    success: true,
   355|    status: 200,
   356|    response: {
   357|      action: 'execute_directly',
   358|      task,
   359|    },
   360|    error: null,
   361|  };
   362|}
   363|
   364|// ─── Core Dispatch Router ──────────────────────────────────────────────────────
   365|
   366|/**
   367| * Dispatch a single task to the appropriate platform.
   368| *
   369| * @param {import('./parser.js').Task} task
   370| * @param {Object} [options]
   371| * @param {boolean} [options.dryRun=false] - If true, return what would be dispatched without calling APIs
   372| * @returns {Promise<DispatchResult>}
   373| */
   374|export async function dispatchTask(task, options = {}) {
   375|  const config = await getConfig();
   376|  const platform = detectPlatform(task.assignee, config);
   377|
   378|  if (options.dryRun) {
   379|    return {
   380|      taskId: task.id,
   381|      assignee: task.assignee,
   382|      platform,
   383|      success: true,
   384|      status: null,
   385|      response: { dryRun: true, wouldDispatchTo: platform },
   386|      error: null,
   387|    };
   388|  }
   389|
   390|  switch (platform) {
   391|    case 'paperclip':
   392|      return dispatchToPaperclip(task);
   393|    case 'openclaw':
   394|      return dispatchToOpenClaw(task);
   395|    case 'hermes':
   396|      return dispatchToHermes(task);
   397|    default:
   398|      return {
   399|        taskId: task.id,
   400|        assignee: task.assignee,
   401|        platform: 'unknown',
   402|        success: false,
   403|        status: null,
   404|        response: null,
   405|        error: `Unknown platform for assignee "${task.assignee}". Cannot route.`,
   406|      };
   407|  }
   408|}
   409|
   410|// ─── Wave-Aware Execution ──────────────────────────────────────────────────────
   411|
   412|/**
   413| * @typedef {Object} WaveResult
   414| * @property {number} wave
   415| * @property {DispatchResult[]} results
   416| * @property {boolean} allSucceeded
   417| */
   418|
   419|/**
   420| * Dispatch all tasks in a plan, wave by wave.
   421| * Dispatches all tasks in wave N in parallel, waits for completion,
   422| * then proceeds to wave N+1.
   423| *
   424| * @param {import('./parser.js').Task[]} tasks - All tasks from a plan
   425| * @param {Object} [options]
   426| * @param {boolean} [options.dryRun=false] - Dry-run mode
   427| * @param {boolean} [options.stopOnWaveFailure=false] - Stop if any task in a wave fails
   428| * @param {(result: WaveResult) => void} [options.onWaveComplete] - Callback after each wave
   429| * @returns {Promise<WaveResult[]>}
   430| */
   431|export async function dispatchByWaves(tasks, options = {}) {
   432|  const waves = groupByWave(tasks);
   433|  const results = [];
   434|
   435|  for (const [waveNum, waveTasks] of waves) {
   436|    // Dispatch all tasks in this wave concurrently
   437|    const waveResults = await Promise.all(
   438|      waveTasks.map(task => dispatchTask(task, { dryRun: options.dryRun }))
   439|    );
   440|
   441|    const waveResult = {
   442|      wave: waveNum,
   443|      results: waveResults,
   444|      allSucceeded: waveResults.every(r => r.success),
   445|    };
   446|
   447|    results.push(waveResult);
   448|
   449|    if (options.onWaveComplete) {
   450|      options.onWaveComplete(waveResult);
   451|    }
   452|
   453|    // Optionally stop on failure
   454|    if (options.stopOnWaveFailure && !waveResult.allSucceeded) {
   455|      break;
   456|    }
   457|  }
   458|
   459|  return results;
   460|}
