   462|/**
   463| * Load routing config from a config.json file and validate assignees.
   464| *
   465| * @param {string} configPath - Path to config.json
   466| * @returns {Promise<Object>} Parsed config
   467| */
   468|export async function loadConfig(configPath) {
   469|  const raw = await readFile(configPath, 'utf-8');
   470|  return JSON.parse(raw);
   471|}
   472|
   473|/**
   474| * High-level: parse a plan file, dispatch all tasks wave-by-wave.
   475| *
   476| * @param {string} planPath - Path to PLAN.md file
   477| * @param {Object} [options]
   478| * @param {boolean} [options.dryRun=false]
   479| * @param {boolean} [options.stopOnWaveFailure=false]
   480| * @param {(result: WaveResult) => void} [options.onWaveComplete]
   481| * @returns {Promise<{meta: import('./parser.js').TaskMeta, waveResults: WaveResult[]}>}
   482| */
   483|export async function executePlan(planPath, options = {}) {
   484|  // Dynamic import to avoid circular dependency issues
   485|  const { parsePlanFile } = await import('./parser.js');
   486|  const plan = await parsePlanFile(planPath);
   487|
   488|  const waveResults = await dispatchByWaves(plan.tasks, options);
   489|
   490|  return {
   491|    meta: plan.meta,
   492|    waveResults,
   493|  };
